#include <stdio.h>
#include <math.h>

int main() {
    int n;
    scanf("%d", &n);
    int x = n;
    int a[1000]; // Assuming a reasonable maximum size
    int count = 0;
    a[count++] = x;

    for (int i = 2; i <= (int)sqrt(n); i++) {
        while (n % i == 0) {
            a[count++] = n / i;
            n = n / i;
        }
    }

    if (a[count-1] != 1) {
        a[count++] = 1;
    }

    for (int i = 0; i < count - 1; i++) {
        printf("%d ", a[i]);
    }
    printf("%d", a[count-1]);

    return 0;
}
